  ('social-worker-moex-01110', 'social-worker', 'social-worker-moex-110-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於危機干預（crisisintervention）的敘述，下列何者錯誤？', '["所謂危機是指每一個人在其生活當中都可能遭遇到的經驗", "在失衡的狀態中，人們會本能地努力奮鬥以回復生活均衡", "舒緩個案情緒與建立關係是危機干預第一個重要操作步驟", "廣義的危機干預是針對危機狀態的個人進行預估與處遇"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "d2632f5986ed", "answer_pdf_sha1": "86c7fc48aade", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
